// ─── Build the Claude prompt from all form fields ───────────────────────────
const d = $input.first().json;

const prompt = `You are an automation consultant analyzing a discovery questionnaire from a potential client in the event operations space. Your job is to identify the highest-impact automation opportunities and produce a prioritized, opinionated build list for a builder who uses n8n and the Claude API.

Here is the completed discovery questionnaire:

## ABOUT THE CLIENT
Name: ${d.name || 'Not provided'}
Role: ${d.role || 'Not specified'}
Company: ${d.company || 'Not specified'}
Email: ${d.email || 'Not provided'}
Team size: ${d.team_size || 'Not specified'}

## CAPACITY CONTEXT (they recently lost two team members)
${d.capacity_gap || 'Not provided'}

## EVENT VOLUME
Events per year: ${d.events_per_year || 'Not specified'}
Average attendees per event: ${d.avg_attendees || 'Not specified'}
Event types they run: ${d.event_types || 'Not specified'}
Busiest season: ${d.busiest_season || 'Not specified'}

## WHERE THEIR TIME GOES (1 = barely any · 5 = consumes their week)
Registration & intake: ${d.time_registration || 'Not rated'}/5
Attendee communications: ${d.time_communications || 'Not rated'}/5
Vendor & venue coordination: ${d.time_vendor || 'Not rated'}/5
Scheduling & logistics: ${d.time_scheduling || 'Not rated'}/5
Post-event follow-up: ${d.time_post_event || 'Not rated'}/5
Reporting & data: ${d.time_reporting || 'Not rated'}/5
Social media & marketing: ${d.time_social || 'Not rated'}/5

## PAIN POINTS (in their own words)
Task they dread most / biggest time sink:
${d.biggest_time_sink || 'Not provided'}

What's actually falling through the cracks since losing team members:
${d.what_falls_through || 'Not provided'}

## CURRENT TOOLS & STACK
Registration tools: ${d.registration_tools || 'Not specified'}
Communication tools: ${d.comms_tools || 'Not specified'}
Where data lives: ${d.data_tools || 'Not specified'}
Openness to new tools: ${d.open_to_new_tools || 'Not specified'}

What happens manually after someone registers (their exact words):
${d.manual_steps || 'Not provided'}

## REPETITIVE WORK PATTERNS
Things they copy-paste or reformat across systems:
${d.copy_paste || 'Not provided'}

Types of emails they write over and over:
${d.emails_written || 'Not provided'}

Regular reports they produce and who gets them:
${d.reports_created || 'Not provided'}

## PRIORITIES & GOALS
The one thing they'd eliminate from their plate tomorrow:
${d.biggest_pain || 'Not provided'}

What success looks like in 90 days: ${d.success_looks_like || 'Not specified'}

Anything else they want you to know:
${d.anything_else || 'None'}

---

Based on this discovery, produce a structured analysis with exactly these sections:

**SITUATION SUMMARY**
3-4 sentences. What's really going on here — the operational reality, not a restatement of the facts. What the capacity gap means in practical terms for their day-to-day. What the biggest risk is if nothing changes.

**TOP AUTOMATION OPPORTUNITIES** (ranked by impact-to-effort ratio, highest first)
For each opportunity, include:
- A short name for the automation
- The exact manual work it eliminates
- Estimated time saved per event or per week
- Build complexity: Low / Medium / High — and why
- Stack: exactly which tools to connect (e.g. rSchoolToday webhook → n8n → SendGrid, or Eventbrite API → n8n → Airtable → Gmail). Be specific to what they told you they use.
- Trigger: what event kicks it off
- Output: what it produces or sends

**RECOMMENDED BUILD ORDER**
First, second, third — with a one-sentence rationale for each. Be opinionated. Prioritize based on what's actively falling through the cracks and what will relieve the most pressure fastest given their reduced headcount.

**QUICK WINS (live in under a week)**
Anything achievable with minimal effort that would provide immediate relief. These should be the first thing you talk about.

**STACK NOTES**
Honest assessment of their current tools. What integrations will be smooth, what will be painful, where the data gaps are, and what to watch out for.

**ONE QUESTION BEFORE BUILDING**
The single most important clarifying question — the one whose answer would most change your recommendations. One question only.

Be specific and direct throughout. Use their exact words back to them where it makes the point stronger. No generic automation advice — every recommendation should be traceable to something they actually told you.`;

// Serialize the full Claude API request body here — avoids n8n expression
// parser choking on the prompt's special characters and newlines.
const claude_request_body = JSON.stringify({
  model: 'claude-sonnet-4-6',
  max_tokens: 4096,
  messages: [{ role: 'user', content: prompt }]
});

return [{
  json: {
    prompt,
    claude_request_body,
    submitter_name: d.name || 'Unknown',
    submitter_email: d.email || '',
    submitted_at: d.submitted_at || new Date().toISOString()
  }
}];

// ─── Extract Claude's text response ────────────────────────────────────────
const claudeResponse = $input.first().json;
const analysis = claudeResponse.content?.[0]?.text ?? 'No response from Claude.';

// Pull submitter info from the Build Prompt node
const submitterName = $('Build Claude Prompt').first().json.submitter_name;
const submitterEmail = $('Build Claude Prompt').first().json.submitter_email;
const submittedAt = $('Build Claude Prompt').first().json.submitted_at;

// Format a clean HTML email body
const htmlBody = `
<div style="font-family: 'Inter', -apple-system, sans-serif; max-width: 720px; margin: 0 auto; color: #0A0F1A;">
  <div style="background: #0A0F1A; padding: 32px; border-radius: 8px 8px 0 0;">
    <div style="font-family: monospace; font-size: 10px; letter-spacing: 0.2em; text-transform: uppercase; color: #7FA9B8; margin-bottom: 8px;">Norr AI · Discovery Analysis</div>
    <div style="font-family: 'Inter Tight', sans-serif; font-weight: 700; font-size: 22px; color: #FAFAF7; letter-spacing: -0.03em;">Event Ops Discovery — ${submitterName}</div>
    <div style="font-size: 12px; color: #6A6F78; margin-top: 6px;">Submitted: ${new Date(submittedAt).toLocaleString('en-US', { timeZone: 'America/Chicago' })} CT · ${submitterEmail}</div>
  </div>
  <div style="background: #FAFAF7; border: 1px solid #E5E4DE; border-top: none; border-radius: 0 0 8px 8px; padding: 32px;">
    <div style="white-space: pre-wrap; font-size: 14px; line-height: 1.75; color: #3A3F48;">${analysis.replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>').replace(/\n/g, '<br>')}</div>
  </div>
  <div style="text-align: center; padding: 24px; font-size: 11px; color: #9EA3AA; font-family: monospace; letter-spacing: 0.1em;">NORR AI · FARIBAULT, MN · AUTOMATED ANALYSIS</div>
</div>
`;

return [{
  json: {
    analysis,
    html_body: htmlBody,
    submitter_name: submitterName,
    submitter_email: submitterEmail,
    subject: `Discovery analysis — ${submitterName} (Event Ops)`
  }
}];
